import type {
  FunctionComponent,
  ReactElement,
  ReactNode,
  ButtonHTMLAttributes,
  ElementType,
  MouseEvent,
} from 'react';
import type { PolymorphicExoticComponent, WithRef } from '@andes/common';

type DeprecatedColors = 'green' | 'orange' | 'red';

export type Color = {
  backgroundColor?: string;
  borderColor?: string;
  closeIconColorActive?: string;
  closeIconColorHover?: string;
  color?: string;
};

type AssetConfig = {
  color?: Color;
  icon?: ReactElement;
  imageUrl?: string;
  text?: string;
};

type ComponentOnClickOrNothing =
  | {
      /**
       * Callback that triggers when the tag is clicked.
       *
       * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag#props | Documentation}
       */
      onClick?: never;
    }
  | {
      component: ElementType;
      /**
       * Callback that triggers when the tag is clicked.
       *
       * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag#props | Documentation}
       */
      onClick?: ButtonHTMLAttributes<HTMLButtonElement>['onClick'];
    };

type TagSpecificProps = {
  /**
   * Custom asset configuration.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag#props | Documentation}
   */
  asset?: AssetConfig;

  children?: ReactNode;

  /**
   * Custom class.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag#props | Documentation}
   */
  className?: string;

  /**
   * Sets a pointer cursor over the tag.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag#props | Documentation}
   * @default false
   */
  clickable?: boolean;

  /**
   * Close button screen reader label.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag#props | Documentation}
   */
  closeButtonSrLabel?: string;

  /**
   * Applies a color over the tag to show different states. Can be a preset value or a custom color definition.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag#props | Documentation}
   */
  color?: Color | DeprecatedColors | 'caution' | 'negative' | 'positive';

  /**
   * Applies disabled styles to tag, and disables any action.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag#props | Documentation}
   * @default false
   */
  disabled?: boolean;

  /**
   * Custom icon.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag#props | Documentation}
   */
  icon?: ReactElement;

  /**
   * Unique identifier.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag#props | Documentation}
   */
  id?: string;

  /**
   * Label to show in the tag.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag#props | Documentation}
   */
  label: string;

  /**
   * Callback that triggers when the close button is clicked.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag#props | Documentation}
   */
  onClose?: ButtonHTMLAttributes<HTMLButtonElement>['onClick'];

  /**
   * Tag size.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag#props | Documentation}
   * @default 'large'
   */
  size?: 'large' | 'small';

  /**
   * Label for screen readers.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag#props | Documentation}
   */
  srLabel?: string;
};

type TagChoiceSpecificProps = WithRef<HTMLButtonElement> & {
  /**
   * Applies styling to reflect a selected tag as default (uncontrolled behavior).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag#props | Documentation}
   */
  defaultSelected?: boolean;

  /**
   * Callback that triggers when the tag is clicked.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag#props | Documentation}
   */
  onClick?: (event: MouseEvent<HTMLButtonElement>, selected: boolean) => void;

  /**
   * Applies styling to reflect a selected tag (controlled behavior).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag#props | Documentation}
   */
  selected?: boolean;
};

type TagCollapsedSpecificProps = WithRef<HTMLUListElement> & {
  /**
   * Custom content, should be a collection of `<Tag>`.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag#props | Documentation}
   */
  children: Array<ReactElement>;

  /**
   * Limit of tags to show.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag#props | Documentation}
   * @default 2
   */
  limit?: number;
};

type TagProps = ComponentOnClickOrNothing & TagSpecificProps;

type TagChoiceProps = Pick<
  TagSpecificProps,
  | 'asset'
  | 'children'
  | 'className'
  | 'disabled'
  | 'id'
  | 'label'
  | 'size'
  | 'srLabel'
> &
  TagChoiceSpecificProps;

type TagCollapsedProps = Pick<TagSpecificProps, 'disabled' | 'id' | 'srLabel'> &
  TagCollapsedSpecificProps;

/**
 * Tags are compact components that represent complex information in a summarized way. Allowing users to make selections, enter information, or filter content.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/6332d2-tags/b/26f535 | UI Specs}
 * @example
 * import { Tag } from '@andes/tag';
 *
 * const MyComponent = () => (
 *  <Tag
 *   label="Lorem ipsum"
 *   asset={{
 *     imageUrl: 'https://mercadolibre.com/some-image.png',
 *     icon: <MyIcon />,
 *     text: 'LI',
 *   }}
 *  />
 * );
 */
export const Tag: PolymorphicExoticComponent<'div', TagProps>;

/**
 * Tags are compact components that represent complex information in a summarized way. Allowing users to make selections, enter information, or filter content.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/6332d2-tags/b/26f535 | UI Specs}
 * @example
 * import { TagChoice } from '@andes/tag';
 *
 * <TagChoice label="Lorem ipsum" onClick={handleClick} selected={selected} />
 */
export const TagChoice: FunctionComponent<TagChoiceProps>;

/**
 * Tags are compact components that represent complex information in a summarized way. Allowing users to make selections, enter information, or filter content.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/tag | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/6332d2-tags/b/26f535 | UI Specs}
 * @example
 * import { Tag, TagCollapsed } from '@andes/tag';
 *
 * const MyComponent = () => (
 *  <TagCollapsed limit={2} srLabel={i18n.gettext('Tag seleccionados')}>
 *    <Tag label="tag 1" />
 *    <Tag label="tag 2" />
 *    <Tag label="tag 3" />
 *  </TagCollapsed>
 * );
 */
export const TagCollapsed: FunctionComponent<TagCollapsedProps>;

export type AssetProps = AssetConfig;
